import{c as a,Q as o,j as e,m as r}from"./chunks/framework.DpF7k2f3.js";const I=JSON.parse('{"title":"제1장 AI 앱 개발의 진실","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part1-cognition/chapter1.md","filePath":"ko/part1-cognition/chapter1.md"}'),p={name:"ko/part1-cognition/chapter1.md"};function i(n,t,l,s,c,A){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="제1장-ai-앱-개발의-진실" tabindex="-1">제1장 AI 앱 개발의 진실 <a class="header-anchor" href="#제1장-ai-앱-개발의-진실" aria-label="Permalink to &quot;제1장 AI 앱 개발의 진실&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>이 챕터를 읽기 전에, 당신은 AI 앱 개발이 접근 불가능한 분야라고 생각했을 수 있습니다 - 박사 학위 필요, 트랜스포머 아키텍처 이해 필요, 튼튼한 수학적 기초 필요 등.</p><p>이 챕터를 읽고 나면 알게 될 것입니다:</p><ul><li>AI 앱 개발과 AI 연구는 다른 것이며, 진입 장벽이 비교할 수 없을 만큼 다릅니다</li><li>2024-2026년 업계에 무슨 일이 발생했는지, 왜 지금이最佳的入场时机인지</li><li>구인 공고의 요구 사항 중哪些是真的、哪些是虚的</li><li>8명의 실제 전직 사례들 - 다양한 배경의 사람들이 어떻게 들어왔는지</li></ul><hr><h2 id="_1-1-ai-앱-개발이란-ai-연구-ai-인프라와-비교" tabindex="-1">1.1 AI 앱 개발이란? (AI 연구/AI 인프라와 비교) <a class="header-anchor" href="#_1-1-ai-앱-개발이란-ai-연구-ai-인프라와-비교" aria-label="Permalink to &quot;1.1 AI 앱 개발이란? (AI 연구/AI 인프라와 비교)&quot;">​</a></h2><p>먼저 힘든 진실을 말하겠습니다: 대부분의 사람들이 들어가길 원하는 &quot;AI 직무&quot;는 실제로 그들이 생각하는 그 &quot;AI 직무&quot;가 아닙니다.</p><h3 id="세-가지-직업-유형-한-글자-차이-하늘과-땅-차이" tabindex="-1">세 가지 직업 유형, 한 글자 차이, 하늘과 땅 차이 <a class="header-anchor" href="#세-가지-직업-유형-한-글자-차이-하늘과-땅-차이" aria-label="Permalink to &quot;세 가지 직업 유형, 한 글자 차이, 하늘과 땅 차이&quot;">​</a></h3><p>저는 AI 업계 기술 직위를 세 가지 계층으로 나눕니다. 어느 계층에 있는지 명확히 하면, 길을 잘못 갈 일이 없습니다:</p><p><strong>제1층: AI 연구(Research)</strong></p><p>기초 혁신을 하는 계층입니다. 무엇을 할까요? 새 모델 훈련, 트랜스포머 아키텍처 개선, 어텐션 메커니즘 최적화. 이것이 OpenAI, Google DeepMind, Anthropic의 과학자들이 하는 일입니다.</p><p>장벽이 얼마나 높을까요? 이렇게 말しましょう: 이 층에서 발을 붙일 수 있는 사람은 전 세계적으로 수만 명 수준의 엘리트 인재뿐입니다. 필요한 것: 최정상급학회 논문, 박사 학위(또는 동등한 연구 능력), 튼튼한 수학적 기초, 최신 논문에 대한 완벽한 파악.</p><p>급여? 천문학적 숫자. 하지만 우리와는 관계없습니다.</p><p><strong>제2층: AI 인프라(Infrastructure)</strong></p><p>&quot;위 층&quot;을 위한 도구를 만드는 계층입니다. 무엇을 할까요? 훈련 프레임워크 개발(PyTorch/TensorFlow 유지보수), 추론 엔진 최적화(vLLM/TensorRT), 분산 훈련 시스템, GPU 클러스터 관리.</p><p>장벽도同样 높습니다. 시스템 하부 구조, C++ 능력, 딥러닝 프레임워크 원리를 이해해야 합니다. 급여는 연구 직책보다 약간 낮지만, 그래도 절대的高給입니다.</p><p><strong>제3층: AI 앱 개발(Application)</strong></p><p>이것이 이 책이 다루는 내용입니다. 그리고 당신이 아마도 들어갈 수 있는 층입니다.</p><p>무엇을 할까요? 간단히 말하면: 기존 AI 능력을 사용하여 비즈니스 문제를 해결합니다. 구체적으로:</p><ul><li>RAG 시스템을 구축하여 대규모 모델이プライベート 지식庫에 답할 수 있게 함</li><li>프롬프트를 작성하여 AI가 원하는 형식으로 출력하게 함</li><li>에이전트를 구축하여 AI가 자동으로 다단계 작업을 실행하게 함</li><li>API를对接하여 AI 능력을 제품에 통합</li></ul><p>모델을 훈련할 필요 없음, 그래디언트 역전파 이해 필요 없음, 어텐션 공식 손도식 필요 없음. 필요한 것: <strong>기존 AI 능력을 잘 활용하고, 비즈니스 시나리오에 적용하여 상업적 가치를 창출하는 것.</strong></p><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter1.html">中文版阅读</a></p></blockquote>',24)])])}const u=a(p,[["render",i]]);export{I as __pageData,u as default};
